    @Bean
    public OAuth2TokenCustomizer<JwtEncodingContext> jwtCustomizer(RegisteredClientRepository registeredClientRepository) {
        return context -> {
            if (context.getAuthorization() != null && context.getAuthorization().getAuthorizedScopes() != null) {
                Set<String> authorizedScopes = context.getAuthorization().getAuthorizedScopes();
                
                RegisteredClient registeredClient = registeredClientRepository.findByClientId(
                        context.getRegisteredClient().getClientId());
                
                if (registeredClient != null) {
                    Set<String> allowedScopes = registeredClient.getScopes();
                    Set<String> validatedScopes = authorizedScopes.stream()
                            .filter(allowedScopes::contains)
                            .collect(Collectors.toSet());
                    
                    context.getClaims().claim("scope", String.join(" ", validatedScopes));
                    context.getClaims().claim("scp", validatedScopes);
                }
            }
            
            if (context.getPrincipal() != null) {
                context.getClaims().claim("username", context.getPrincipal().getName());
            }
            
            context.getClaims().claim("iss", "http://localhost:9000");
            context.getClaims().claim("client_id", context.getRegisteredClient().getClientId());
        };
    }
